exercises.solution:
function assemblePrompt(base, sections, maxChars) {
  let out = base;
  for (const s of sections) {
    if (!s) continue;
    if (out.length + s.length <= maxChars) {
      out += s;
    } else {
      const remaining = maxChars - out.length;
      if (remaining > 10) out += s.slice(0, remaining) + '[...truncated]';
      break;
    }
  }
  return out;
}

